    #[test]
    fn error_buffer_truncates_and_nul_terminates() {
        // copy_to_buf must truncate an oversized message to fit and keep the
        // trailing NUL (the one piece of pointer arithmetic in the file).
        let path = CString::new("/no/such/directory/deeply/nested/missing/case.m").unwrap();
        let mut err = [0x7f as c_char; 16]; // prefill nonzero so the NUL is visible
        let c =
            unsafe { pio_parse_file(path.as_ptr(), std::ptr::null(), err.as_mut_ptr(), err.len()) };
        assert!(c.is_null());
        let nul = err
            .iter()
            .position(|&b| b == 0)
            .expect("buffer must be NUL-terminated");
        assert!(nul <= 15);
    }

    #[test]
    fn truncation_lands_on_a_utf8_char_boundary() {
        // "aé€" is 1+2+3 bytes; a 6-byte buffer fits 5 message bytes, which
        // would split '€'. The copy must back up to "aé" instead of emitting a
        // dangling partial codepoint.
        let mut buf = [0x7f as c_char; 6];
        unsafe { copy_to_buf(buf.as_mut_ptr(), buf.len(), "aé€") };
        let s = unsafe { CStr::from_ptr(buf.as_ptr()) }
            .to_str()
            .expect("truncated message must be valid UTF-8");
        assert_eq!(s, "aé");

        // A message that fits is copied whole.
        let mut buf = [0x7f as c_char; 8];
        unsafe { copy_to_buf(buf.as_mut_ptr(), buf.len(), "aé€") };
        let s = unsafe { CStr::from_ptr(buf.as_ptr()) }.to_str().unwrap();
        assert_eq!(s, "aé€");
    }

